def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    # Slide 3 is index 2
    slide = prs.slides[2]
    # Find all text runs that are experiment names by comparing to original
    original_names = ['Norman Triplett Experiment', 'Milgram’s Shock Experiment' 'Leon Festinger studies of Cognitive Dissonance', 'David Hamilton and Robert Gifford (1976)', 'Richard T. La Piere’s hospitality Study']
    # Now check hyperlink presence for each name in modified
    missing_links = []
    found_names = set()
    for shape in slide.shapes:
        if not shape.has_text_frame:
            continue
        for p in shape.text_frame.paragraphs:
            for run in p.runs:
                text = run.text.strip()
                if text in original_names:
                    found_names.add(text)
                    hlink = run.hyperlink.address if hasattr(run, 'hyperlink') else None
                    if not hlink:
                        missing_links.append(text)
    if missing_links:
        reason = f"The following experiment names on slide 3 are missing hyperlinks: {missing_links}" 
        score = 1.0 - len(missing_links)/len(original_names)
        return (reason, max(0.0, score))
    reason = "All experiment names on slide 3 are hyperlinked."
    return (reason, 1.0)

def compute_score() -> tuple[str, float]:
    import re
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[2]
    # Collect all hyperlinks for experiment names

    links = []
    texts = []
    for shape in slide.shapes:
        if not shape.has_text_frame:
            continue

        text = shape.text.strip()
        if 'Gifford' in text:
            text += ' Illusory Correlation'

        hlink = None
        for p in shape.text_frame.paragraphs:
            for run in p.runs:
                if hasattr(run, 'hyperlink'):
                    hlink = run.hyperlink.address
                    break

        if hlink:
            texts.append(text)
            links.append(hlink)
    if not links:
        return ("No hyperlinks found on experiment names in slide 3.", 0.0)
    # Check each hyperlink: must be to Wikipedia page for experiment or researcher
    incorrect = []
    for text, url in zip(texts, links):
        if not url.lower().startswith("https://en.wikipedia.org/wiki/"):
            incorrect.append((text, url))
            continue
        # Check if the experiment name or related researcher is in the URL
        words = re.split(r"\s|,|:|\(|\)", text)
        url_tail = url.rsplit("/wiki/", 1)[-1].replace("_", " ").lower()
        relevant = any(word.lower() in url_tail for word in words if word)
        if not relevant:
            incorrect.append((text, url))
    score = 1.0 - len(incorrect)/len(links)
    if incorrect:
        reason = f"The following experiment names have incorrect Wikipedia links: {incorrect}"
        return (reason, max(0.0, score))
    return ("All hyperlinks point to correct Wikipedia pages.", 1.0)

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[2]
    # Find all experiment names from original
    original_prs = Presentation(original_ppt_path)
    original_slide = original_prs.slides[2]
    experiment_names = set()
    for shape in original_slide.shapes:
        if not shape.has_text_frame:
            continue
        for p in shape.text_frame.paragraphs:
            for run in p.runs:
                text = run.text.strip()
                if text:
                    experiment_names.add(text)
    extraneous = []
    for shape in slide.shapes:
        if not shape.has_text_frame:
            continue
        for p in shape.text_frame.paragraphs:
            for run in p.runs:
                text = run.text.strip()
                hlink = run.hyperlink.address if hasattr(run, 'hyperlink') else None
                if hlink and text not in experiment_names:
                    extraneous.append((text, hlink))
    if extraneous:
        reason = f"Found extraneous hyperlinks on slide 3: {extraneous}"
        score = 1.0 - len(extraneous)/(len(extraneous)+len(experiment_names))
        return (reason, max(0.0, score))
    return ("No extraneous hyperlinks found on slide 3.", 1.0)
